export const categories: Category[] = ["News", "Entertainment", "General", "Movies", "Sports", "Music", "Kids", "Religious", "Lifestyle", "International"];

export function getChannel(slug: string): Channel | undefined {
  return channels.find((c) => c.slug === slug);
}

export function relatedChannels(slug: string, limit = 8): Channel[] {
  const current = getChannel(slug);
  if (!current) return channels.slice(0, limit);
  const same = channels.filter((c) => c.slug !== slug && c.category === current.category);
  const others = channels.filter((c) => c.slug !== slug && c.category !== current.category);
  return [...same, ...others].slice(0, limit);
}
